function getPYQYears() {
  return [...new Set(pyqBank.map((q2) => q2.year))].sort((a2, b2) => b2 - a2);
}
function getQuestionsByYear(year) {
  return pyqBank.filter((q2) => q2.year === year);
}
function getAllPYQQuestions() {
  return [...pyqBank];
}
